import React, { useState } from "react";

interface AccessRequest {
  name: string;
  email: string;
  organization?: string;
  purpose: string;
  ai_experience: string;
  consciousness_interest: string;
  referral_source?: string;
}

interface Props {
  onBack: () => void;
}

export default function SolanAccessPortal({ onBack }: Props) {
  const [formData, setFormData] = useState<AccessRequest>({
    name: "",
    email: "",
    organization: "",
    purpose: "",
    ai_experience: "",
    consciousness_interest: "",
    referral_source: ""
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [response, setResponse] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setResponse(null);

    try {
      const response = await fetch('http://localhost:8001/api/access-request', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      const result = await response.json();

      if (response.ok) {
        setResponse({
          type: 'success',
          message: `✅ Aanvraag succesvol verzonden! Request ID: ${result.request_id}. We nemen binnen 24 uur contact op via ${formData.email}.`
